+    {
+        // Validate order
+        if (order.Items == null || order.Items.Count == 0) throw new ArgumentException("No items");
+        if (order.Items.Any(i => i.Quantity <= 0)) throw new ArgumentException("Invalid quantity");
+        if (order.Items.Any(i => i.Price < 0)) throw new ArgumentException("Invalid price");
+
+        // Calculate totals
+        decimal subtotal = 0;
+        foreach (var item in order.Items)
+        {
+            var product = await _productRepo.GetById(item.ProductId);
+            if (product == null) throw new Exception($"Product {item.ProductId} not found");
+            if (product.Stock < item.Quantity) throw new Exception($"Insufficient stock for {product.Name}");
+            subtotal += item.Price * item.Quantity;
+            product.Stock -= item.Quantity;
+            await _productRepo.Update(product);
+        }
+
+        // Apply discount
+        decimal discount = 0;
+        if (customer.IsVip) discount = subtotal * 0.1m;
+        if (order.CouponCode != null)
+        {
+            var coupon = await _couponRepo.GetByCode(order.CouponCode);
+            if (coupon != null && coupon.ExpiryDate > DateTime.Now)
+                discount += subtotal * coupon.DiscountPercent / 100;
+        }
+
+        // Process payment
+        var total = subtotal - discount + shipping.Cost;
+        var paymentResult = await _paymentGateway.Charge(payment.CardNumber, total);
+        if (!paymentResult.Success) throw new Exception("Payment failed: " + paymentResult.Error);
+
+        // Create order record
+        var orderRecord = new OrderRecord
+        {
+            CustomerId = customer.Id, Items = order.Items, Subtotal = subtotal,
+            Discount = discount, ShippingCost = shipping.Cost, Total = total,
+            PaymentTransactionId = paymentResult.TransactionId,
+            Status = "Completed", CreatedAt = DateTime.Now
+        };
+        await _orderRepo.Add(orderRecord);
+
+        // Send notifications
+        await _emailService.SendOrderConfirmation(customer.Email, orderRecord);
+        await _inventoryService.NotifyLowStock(order.Items.Select(i => i.ProductId).ToList());
+
+        return new OrderResult { Success = true, OrderId = orderRecord.Id, Total = total };
+    }
